async function initializeUcid() {
  if (!uploader_storage.getState().ucid) {
    uploader_storage.getState().ucid = esm_browser_v4();
    await uploader_storage.save();
  }
}

/**
 * Starts CDP, which will trigger sending aggregated metrics to the CDP
 * server on a schedule.
 *
 * @param {Object} cdp CDP configuration (URLs, bearer)
 * @param {number} errorRetryDelay
 *        Error retry interval in milliseconds
 * @ignore
 */
async function uploader_start(cdp, errorRetryDelay = 1 * time.MILLIS_IN_HOUR) {
  if (!cdp.pingUrl) {
    throw new Error("No CDP `pingUrl` provided");
  }

  if (!cdp.publicKeyUrl) {
    throw new Error("No CDP `publicKeyUrl` provided");
  }

  if (!cdp.bearer) {
    throw new Error("No CDP `bearer` provided");
  }

  _cdp = cdp;

  uploader_storage.clearState();
  await uploader_storage.load();
  await initializeUcid();
  initializeScheduler(errorRetryDelay);
}

async function uploader_reset() {
  uploader_stop();
  uploader_storage.clearState();
  await uploader_storage.save();
}

function uploader_stop() {
  if (!_scheduler) {
    return;
  }

  _scheduler.stop();
  _scheduler = null;
}

